
body {
  margin: 0;
  padding: 0;
  font-family: 'Microsoft YaHei', 'PingFang SC', sans-serif;
}

.status-panel {
  width: 100%;
  max-width: 320px;
  margin: 0 auto;
}

.panel {
  background: linear-gradient(160deg, rgba(30, 35, 50, 0.92), rgba(20, 25, 40, 0.95));
  border-radius: 14px;
  padding: 14px 16px;
  border: 1px solid rgba(255, 255, 255, 0.08);
  box-shadow: 0 6px 20px rgba(0, 0, 0, 0.25);
  color: #d0d8e8;
  font-size: 13px;
}

.commander-panel {
  .panel-header {
    display: flex;
    align-items: center;
    gap: 7px;
    font-size: 15px;
    font-weight: 700;
    color: #c9a96e;
    padding-bottom: 10px;
    margin-bottom: 8px;
    border-bottom: 1px solid rgba(201, 169, 110, 0.2);
  }
}

.eternal-panel {
  border-color: rgba(120, 160, 220, 0.2);
  box-shadow: 0 6px 24px rgba(80, 120, 200, 0.12);

  .star-header {
    display: flex;
    align-items: center;
    gap: 7px;
    font-size: 15px;
    font-weight: 700;
    color: #8ab4f8;
    padding-bottom: 10px;
    margin-bottom: 8px;
    border-bottom: 1px solid rgba(138, 180, 248, 0.2);

    .fa-star { color: #f1c40f; }
    .stage-badge {
      margin-left: auto;
      font-size: 11px;
      padding: 2px 8px;
      border-radius: 8px;
      font-weight: 600;
    }
    .stage-pure { background: rgba(155, 200, 255, 0.2); color: #9bc8ff; }
    .stage-awake { background: rgba(241, 196, 15, 0.2); color: #f1c40f; }
    .stage-indulge { background: rgba(231, 76, 60, 0.2); color: #e74c3c; }
  }
}

.info-row {
  display: flex;
  align-items: center;
  gap: 6px;
  padding: 3px 0;
  font-size: 12px;
  color: #99aabb;

  .info-icon { flex-shrink: 0; }
}

.collar-off { color: #889999; }

.info-compact {
  display: flex;
  gap: 12px;
  font-size: 11px;
  color: #8899aa;
  padding: 1px 0;
  flex-wrap: wrap;
}

.stat-item {
  margin-top: 8px;
}

.stat-head {
  display: flex;
  align-items: center;
  gap: 6px;
  margin-bottom: 3px;

  .stat-icon { width: 14px; font-size: 11px; }
  .stat-label { flex: 1; font-size: 12px; color: #aabbcc; }
  .stat-num { font-size: 12px; font-weight: 600; color: #ccddee; font-variant-numeric: tabular-nums; }

  .lewd { color: #e74c3c; }
  .arousal { color: #f39c12; }
  .adapt { color: #2ecc71; }
}

.stat-bar {
  height: 6px;
  background: rgba(255, 255, 255, 0.06);
  border-radius: 3px;
  overflow: hidden;

  .stat-fill {
    height: 100%;
    border-radius: 3px;
    transition: width 0.5s ease;
  }
  .lewd-fill { background: linear-gradient(90deg, #e74c3c, #ff6b6b); }
  .arousal-fill { background: linear-gradient(90deg, #f39c12, #f7dc6f); }
  .adapt-fill { background: linear-gradient(90deg, #2ecc71, #58d68d); }
}

/* ===== 攻守仪表盘 ===== */
.gauge-section {
  margin-top: 14px;
  padding-top: 10px;
  border-top: 1px solid rgba(255, 255, 255, 0.06);
  display: flex;
  flex-direction: column;
  align-items: center;
}

.gauge-title {
  font-size: 12px;
  color: #aabbcc;
  margin-bottom: 4px;
  display: flex;
  align-items: center;
  gap: 5px;

  .fa-tachometer-alt { color: #8ab4f8; }
}

.gauge-svg {
  width: 180px;
  height: auto;
  display: block;
}

.gauge-active {
  transition: d 0.5s ease;
}

.gauge-needle {
  transition: all 0.5s ease;
}

.gauge-value {
  font-size: 20px;
  font-weight: 700;
  color: #fff;
  margin-top: -14px;
  font-variant-numeric: tabular-nums;
}

.gauge-label {
  font-size: 11px;
  color: #8899aa;
  margin-top: -2px;
}

/* ===== 身体状态 ===== */
.body-state {
  margin-top: 12px;
  padding-top: 10px;
  border-top: 1px solid rgba(255, 255, 255, 0.06);
}

.body-state-title {
  font-size: 12px;
  color: #aabbcc;
  margin-bottom: 6px;
  display: flex;
  align-items: center;
  gap: 5px;
}

.body-tags {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 5px;
}

.body-tag {
  font-size: 11px;
  padding: 4px 7px;
  border-radius: 6px;
  background: rgba(255, 255, 255, 0.04);
  color: #99aabb;
  white-space: nowrap;
}

/* ===== 心理想法 ===== */
.thought-bubble {
  margin-top: 10px;
  padding: 8px 10px;
  background: rgba(138, 180, 248, 0.08);
  border-left: 2px solid rgba(138, 180, 248, 0.4);
  border-radius: 0 6px 6px 0;
  font-size: 11px;
  color: #99aacc;
  font-style: italic;
  line-height: 1.5;

  .fa-quote-left {
    color: rgba(138, 180, 248, 0.3);
    margin-right: 4px;
    font-size: 10px;
  }
}
